import { jsx } from 'react/jsx-runtime';
import { forwardRef, useRef, useImperativeHandle } from 'react';
import { TextField } from '../TextField/TextField.js';

const OldMaskField = forwardRef(({ size = 'medium', autoComplete = 'off', inputClassName: externalInputClassName, fullWidth = false, error = false, disabled = false, dataTestId = 'TextField', isClickableAdornment = true, maskedInstance, onChange, ...props }, ref) => {
    const localRef = useRef(null);
    useImperativeHandle(ref, () => localRef.current);
    const handleChange = (event) => {
        const { value: updatedInputValue } = event.target;
        maskedInstance?.resolve(updatedInputValue);
        event.target.value = maskedInstance.value;
        onChange?.(event);
    };
    return (jsx("div", { "data-testid": "MaskField", children: jsx(TextField, { ref: localRef, size: size, autoComplete: autoComplete, inputClassName: externalInputClassName, fullWidth: fullWidth, error: error, disabled: disabled, dataTestId: dataTestId, isClickableAdornment: isClickableAdornment, onChange: handleChange, ...props }) }));
});

export { OldMaskField };
